// Simple and reliable health news filter
const healthNews = [];

for (const item of $input.all()) {
  const title = (item.json.title || '').toLowerCase();
  const description = (item.json.description || '').toLowerCase();
  const searchText = title + ' ' + description;

  // Check for health keywords
  const isHealth = searchText.includes('health') || 
                   searchText.includes('medical') || 
                   searchText.includes('hospital') ||
                   searchText.includes('doctor') ||
                   searchText.includes('disease') ||
                   searchText.includes('patient') ||
                   searchText.includes('vaccine') ||
                   searchText.includes('covid') ||
                   searchText.includes('virus') ||
                   searchText.includes('medicine');

  if (isHealth) {
    healthNews.push(item);
  }
}

return healthNews;

// Get today's date dynamically
const today = new Date();
today.setHours(0, 0, 0, 0);

const tomorrow = new Date(today);
tomorrow.setDate(today.getDate() + 1);
tomorrow.setHours(0, 0, 0, 0);

// Filter and process input items
const filteredItems = [];

for (const item of $input.all()) {
  const pubDateString = item.json.pubDate || 
                        item.json.isoDate || 
                        item.json.published || 
                        item.json.date ||
                        item.json.publishedDate;

  const title = (item.json.title || '').toLowerCase();
  const description = (item.json.description || item.json.contentSnippet || '').toLowerCase();

  // ✅ Keywords for crypto market condition
  const isCryptoMarket = title.includes('crypto') || description.includes('crypto') ||
                         title.includes('bitcoin') || description.includes('bitcoin') ||
                         title.includes('ethereum') || description.includes('ethereum') ||
                         title.includes('market') || description.includes('market') ||
                         title.includes('price') || description.includes('price');

  if (pubDateString && isCryptoMarket) {
    const pubDate = new Date(pubDateString);

    // ✅ Check if the publication date is today
    if (pubDate >= today && pubDate < tomorrow) {
      let newsSource = 'Cointelegraph';
      if (item.json.link) {
        try {
          const url = new URL(item.json.link);
          const hostname = url.hostname.replace('www.', '').replace('feeds.', '').replace('rss.', '');
          newsSource = hostname.charAt(0).toUpperCase() + hostname.slice(1);
        } catch (e) {
          newsSource = 'Cointelegraph';
        }
      }

      filteredItems.push({
        json: {
          title: item.json.title || 'No Title',
          description: item.json.description || item.json.contentSnippet || '',
          link: item.json.link || '',
          pubDate: pubDateString,
          newsSource: newsSource
        }
      });
    }
  }
}

// ✅ Return only today's crypto market news
return filteredItems;

